INSERT INTO course (slug, title, tagline, icon, category, audience, price_from, price_unit, price_note, summary, highlights, languages, duration, cta_label, sections, cost_per_session, active) VALUES ('fahrstunden-auto', 'Fahrstunden Auto', 'Sicher und entspannt zum Autofahren', 'steering-wheel', 'auto', 'auto', 88, 'pro Lektion', 'ab CHF 88 im 10er-Abo', 'Individuelle Fahrstunden in sicheren, komfortablen Autos – auf Wunsch auf Italienisch, Spanisch, Französisch oder Englisch.', '["Moderne, sichere Fahrschulautos","Unterricht in D, IT, FR, ES, EN","Flexible Terminplanung","Vorbereitung auf die praktische Prüfung"]'::jsonb, '["Deutsch","Italienisch","Spanisch","Französisch","Englisch"]'::jsonb, NULL, 'Fahrstunde buchen', '[{"heading":"So läuft deine Fahrstunde ab","body":["Wir holen dich dort ab, wo du stehst – ob erste Fahrstunde überhaupt oder Feinschliff kurz vor der Prüfung. Jede Lektion ist auf dein Tempo und deine Lernziele zugeschnitten.","Unsere Fahrzeuge sind sicher, komfortabel und alltagstauglich – so lernst du in Bedingungen, die du nach der Prüfung auch wirklich antriffst."]},{"heading":"Preise","body":["CHF 95.– pro Lektion (Barzahlung), CHF 90.– im 5er-Abo, CHF 88.– im 10er-Abo.","Einmalige Versicherungspauschale von CHF 100.– bei der ersten Fahrstunde."]},{"heading":"Mehrsprachiger Unterricht","body":["Fährst du dich in deiner Muttersprache sicherer? Kein Problem – wir unterrichten auf Deutsch, Italienisch, Spanisch, Französisch und Englisch."]}]'::jsonb, 0, true);
INSERT INTO course (slug, title, tagline, icon, category, audience, price_from, price_unit, price_note, summary, highlights, languages, duration, cta_label, sections, cost_per_session, active) VALUES ('fahrstunden-motorrad', 'Fahrstunden Motorrad', 'Individuelle Töff-Fahrstunden', 'bike', 'motorrad', 'motorrad', 95, 'pro Lektion', NULL, 'Praxislektionen auf dem Motorrad für alle Kategorien (A1, A beschränkt, A) – individuell begleitet, sicher aufgebaut.', '["Für A1, A (beschränkt) und A","Aufbau von Fahrzeugbeherrschung Schritt für Schritt","Kombinierbar mit dem Motorradgrundkurs","Vorbereitung auf die praktische Prüfung"]'::jsonb, 'null'::jsonb, NULL, 'Fahrstunde buchen', '[{"heading":"Vom ersten Anfahren bis zur Prüfungsroute","body":["Egal ob du gerade erst deinen Lernfahrausweis für die Kategorie A1 gemacht hast oder auf die unbeschränkte Kategorie A hinarbeitest – wir bauen deine Fahrstunden systematisch auf: Fahrzeugbeherrschung, Verkehrssituationen, Prüfungsroute."]},{"heading":"Kombination mit dem Grundkurs","body":["Die praktische Grundausbildung (Motorradgrundkurs) ist obligatorisch und Voraussetzung für die Prüfungsanmeldung. Individuelle Fahrstunden ergänzen den Grundkurs ideal und geben dir zusätzliche Sicherheit im Verkehr."]}]'::jsonb, 0, true);
INSERT INTO course (slug, title, tagline, icon, category, audience, price_from, price_unit, price_note, summary, highlights, languages, duration, cta_label, sections, cost_per_session, active) VALUES ('motorradgrundkurs', 'Motorradgrundkurs', 'Die obligatorische praktische Grundausbildung', 'bike', 'motorrad', 'motorrad', NULL, 'auf Anfrage', NULL, '12 Stunden praktische Grundausbildung – Pflicht für alle Motorrad-Kategorien (A1, A beschränkt, A) vor der praktischen Prüfung.', '["Obligatorisch für A1, A beschränkt und A","Fahrzeugbeherrschung & Gefahrenbremsung","Kleine Gruppen, viel Übungszeit","Kursbestätigung für die Prüfungsanmeldung"]'::jsonb, 'null'::jsonb, '12 Stunden praktische Grundausbildung', 'Kursdatum wählen', '[{"heading":"Was dich erwartet","body":["Die praktische Grundausbildung vermittelt dir die sichere Beherrschung des Motorrads: Balance, Bremstechnik, Ausweichmanöver und Kurvenfahren – in kleinen Gruppen und mit viel individueller Übungszeit auf unserem Verkehrsübungsplatz.","Nach Abschluss erhältst du die Kursbestätigung, die du für die Anmeldung zur praktischen Prüfung benötigst."]},{"heading":"Seit OPERA-3","body":["Seit der Revision OPERA-3 gelten neue Alterslimiten je nach Kategorie (A1 45 km/h ab 15, A1 125cm³ ab 16, A beschränkt 35 kW ab 18, A unbeschränkt ab 20 mit 2 Jahren Vorerfahrung auf einem 35-kW-Motorrad). Wir beraten dich, welche Kategorie und welcher Kurs für dich passt."]}]'::jsonb, 0, true);
INSERT INTO course (slug, title, tagline, icon, category, audience, price_from, price_unit, price_note, summary, highlights, languages, duration, cta_label, sections, cost_per_session, active) VALUES ('vku', 'VKU – Verkehrskunde-Unterricht', 'Der obligatorische Theoriekurs vor den Fahrstunden', 'book-open', 'pflicht', 'vku-btu', 190, 'inkl. Unterlagen', 'ab CHF 190', '4 Doppellektionen, die dich auf sicheres und vorausschauendes Fahren vorbereiten – Pflicht für den Lernfahrausweis Kategorie B.', '["4 Abende, Mo–Do, 19.00–21.00 Uhr","Kleine Klassen, praxisnahe Fallbeispiele","Ab CHF 190 inkl. Kursunterlagen","Regelmässig neue Starttermine"]'::jsonb, 'null'::jsonb, '4 Doppellektionen (Mo–Do, 19.00–21.00 Uhr)', 'VKU-Termin wählen', '[{"heading":"Was ist der VKU?","body":["Der Verkehrskundeunterricht ist in der Schweiz für alle obligatorisch, die den Führerausweis Kategorie B erwerben möchten. In 4 Doppellektionen lernst du vorausschauendes, partnerschaftliches Fahrverhalten – die beste Grundlage für deine Fahrstunden."]},{"heading":"Ablauf & Preis","body":["Der Kurs findet an 4 Abenden statt (Montag bis Donnerstag, jeweils 19.00–21.00 Uhr). Kosten ab CHF 190.– inklusive Kursunterlagen."]}]'::jsonb, 0, true);
INSERT INTO course (slug, title, tagline, icon, category, audience, price_from, price_unit, price_note, summary, highlights, languages, duration, cta_label, sections, cost_per_session, active) VALUES ('btu', 'BTU – Basis-Theorie-Unterricht', 'Fundiertes Theoriewissen für die Prüfung', 'book-open', 'pflicht', 'vku-btu', 200, 'inkl. Unterlagen', NULL, '4 Doppellektionen zu den 6 Theoriethemen – inklusive 8 gratis Übungsstunden Prüfungsfragebogen.', '["4 Doppellektionen zu 6 Theoriethemen","CHF 200 inkl. Kursunterlagen","8 Stunden Prüfungsfragebogen gratis inklusive","Ideale Vorbereitung auf die Theorieprüfung"]'::jsonb, 'null'::jsonb, '4 Doppellektionen', 'BTU-Termin wählen', '[{"heading":"Inhalt","body":["Der Basis-Theorie-Unterricht behandelt die 6 vorgeschriebenen Theoriethemen und bereitet dich gezielt auf die Theorieprüfung vor."]},{"heading":"Inklusive Übungszeit","body":["Im Preis von CHF 200.– (inkl. Unterlagen) sind zusätzlich 8 Stunden gratis Prüfungsfragebogen-Übung (Bögle) enthalten – du übst so lange, bis du dich sicher fühlst."]}]'::jsonb, 0, true);
INSERT INTO course (slug, title, tagline, icon, category, audience, price_from, price_unit, price_note, summary, highlights, languages, duration, cta_label, sections, cost_per_session, active) VALUES ('nothelferkurs', 'Nothelferkurs', 'Pflichtkurs für jedes Führerausweis-Gesuch', 'heart-pulse', 'pflicht', 'nothelfer', NULL, 'siehe Kursdaten', NULL, 'Der erste Schritt auf dem Weg zum Führerausweis: als Wochenendkurs (Fr/Sa) oder als Abendkurs – Ausweis 6 Jahre gültig.', '["Voraussetzung für jedes Führerausweis-Gesuch","Wochenend- oder Abendformat","Ausweis 6 Jahre gültig","Laufend neue Termine"]'::jsonb, 'null'::jsonb, 'Wochenendkurs (Fr–Sa) oder Abendkurs', 'Nothelferkurs buchen', '[{"heading":"Warum zuerst der Nothelferkurs?","body":["Der Nothelferausweis ist Voraussetzung für das Gesuch um einen Lern- oder Führerausweis – deshalb ist er der erste Schritt auf deinem Weg zum Billett."]},{"heading":"Formate","body":["Wähle zwischen dem kompakten Wochenendkurs (Freitag/Samstag) oder Abendlektionen unter der Woche – beide führen zum gleichen, 6 Jahre gültigen Ausweis."]}]'::jsonb, 0, true);
INSERT INTO course (slug, title, tagline, icon, category, audience, price_from, price_unit, price_note, summary, highlights, languages, duration, cta_label, sections, cost_per_session, active) VALUES ('boegle', 'Bögle', 'Gratis Übung für die Theorieprüfung', 'clipboard-check', 'zusatz', 'boegle', 0, 'gratis', 'kostenlos, keine Anmeldung nötig', 'Jeden Montag 19.00–21.00 Uhr übst du bei uns kostenlos den offiziellen Prüfungsfragebogen – in 9 Sprachen verfügbar.', '["Jeden Montag, 19.00–21.00 Uhr (Einlass bis 20.00 Uhr)","Keine Anmeldung nötig, gratis","Prüfung: 50 Fragen, max. 14 Fehler erlaubt","Verfügbar in 9 Sprachen"]'::jsonb, 'null'::jsonb, 'Montags, 19.00–21.00 Uhr', 'Mehr erfahren', '[{"heading":"Was ist Bögle?","body":["„Bögle“ ist unsere kostenlose Übungslektion für die Theorieprüfung. Die echte Prüfung umfasst 50 Fragen mit einer oder mehreren richtigen Antworten – bestanden ist, wer maximal 14 Fehler macht.","Die Theorieprüfung ist in 9 Sprachen verfügbar: Deutsch, Französisch, Italienisch, Englisch, Spanisch, Portugiesisch, Türkisch, Serbokroatisch und Albanisch."]},{"heading":"So funktioniert''s","body":["Komm einfach vorbei – jeden Montag von 19.00 bis 21.00 Uhr (Einlass bis 20.00 Uhr), ohne Anmeldung. Voraussetzung für die Anmeldung zur echten Theorieprüfung ist ein gültiger Nothelferausweis.","Wer vorab testen möchte, ob er bereit ist: Wir bieten zusätzlich einen kostenlosen Mini-Onlinetest mit 20 Beispielfragen an."]}]'::jsonb, 0, true);
INSERT INTO course (slug, title, tagline, icon, category, audience, price_from, price_unit, price_note, summary, highlights, languages, duration, cta_label, sections, cost_per_session, active) VALUES ('lastwagen', 'Lastwagen', 'Fahrausbildung Kategorie C/CE', 'truck', 'zusatz', 'auto', 140, 'pro praktische Lektion', NULL, 'Praktische und theoretische Lektionen für die Lastwagen-Kategorien.', '["CHF 140 pro praktische Lektion","CHF 25 pro theoretische Lektion","Individuelle Terminplanung"]'::jsonb, 'null'::jsonb, NULL, 'Jetzt anfragen', '[{"heading":"Preise","body":["Praktische Lektion: CHF 140.–. Theoretische Lektion: CHF 25.–."]}]'::jsonb, 0, true);
