INSERT INTO faq_item (question, answer, sort_order) VALUES ('Wie viel kostet der Führerausweis insgesamt?', 'Das hängt von deiner Vorerfahrung und Kategorie ab. Als Richtwert: Nothelferkurs, VKU (ab CHF 190) und rund 10–20 Fahrstunden (ab CHF 88 pro Lektion im Abo) plus die amtlichen Prüfungsgebühren. Wir erstellen dir gerne eine persönliche Kostenschätzung.', 0);
INSERT INTO faq_item (question, answer, sort_order) VALUES ('Wie melde ich mich für einen Kurs an?', 'Wähle unter „Kursdaten & Anmeldung“ dein gewünschtes Datum aus und fülle das Online-Formular aus. Du erhältst danach eine Bestätigung von uns per E-Mail.', 1);
INSERT INTO faq_item (question, answer, sort_order) VALUES ('Was muss ich zur ersten Fahrstunde mitbringen?', 'Deinen Lernfahrausweis, deinen Nothelferausweis sowie bequeme Schuhe. Bei Fragen melde dich einfach vorher bei uns.', 2);
INSERT INTO faq_item (question, answer, sort_order) VALUES ('In welchen Sprachen bietet ihr Unterricht an?', 'Fahrstunden und Theoriekurse bieten wir auf Deutsch, Italienisch, Spanisch, Französisch und Englisch an – sag uns einfach, was für dich am angenehmsten ist.', 3);
INSERT INTO faq_item (question, answer, sort_order) VALUES ('Was ist der Unterschied zwischen VKU und BTU?', 'Der VKU (Verkehrskundeunterricht) ist für alle obligatorisch, die den Führerausweis Kategorie B erwerben. Der BTU (Basis-Theorie-Unterricht) vertieft die 6 Theoriethemen und beinhaltet zusätzlich 8 Stunden gratis Prüfungsfragebogen-Übung.', 4);
INSERT INTO faq_item (question, answer, sort_order) VALUES ('Muss ich mich für „Bögle“ anmelden?', 'Nein – die kostenlose Übungslektion für die Theorieprüfung findet jeden Montag von 19.00 bis 21.00 Uhr (Einlass bis 20.00 Uhr) ohne Anmeldung statt. Einfach vorbeikommen.', 5);
INSERT INTO faq_item (question, answer, sort_order) VALUES ('Wie lange ist der Nothelferausweis gültig?', 'Der Nothelferausweis ist 6 Jahre gültig und Voraussetzung für jedes Führerausweis-Gesuch.', 6);
INSERT INTO faq_item (question, answer, sort_order) VALUES ('Bietet ihr auch Motorrad-Ausbildung an?', 'Ja – von der praktischen Grundausbildung (Motorradgrundkurs) über individuelle Fahrstunden bis zur Vorbereitung auf die praktische Prüfung, für die Kategorien A1, A beschränkt und A.', 7);
INSERT INTO testimonial (name, course, rating, quote, sort_order) VALUES ('Lara M.', 'Fahrstunden Auto', 5, 'Ich war sehr nervös vor meiner ersten Fahrstunde, aber Bruno hat mir die Angst sofort genommen. Erklärt geduldig, bleibt immer ruhig – ich habe die Prüfung im ersten Anlauf bestanden.', 0);
INSERT INTO testimonial (name, course, rating, quote, sort_order) VALUES ('Elira K.', 'VKU & BTU', 5, 'Der Unterricht war super verständlich aufgebaut, auch die Prüfungsfragen im Bögle haben mir enorm geholfen. Danke für die tolle Vorbereitung!', 1);
INSERT INTO testimonial (name, course, rating, quote, sort_order) VALUES ('Marco T.', 'Motorradgrundkurs', 5, 'Kleine Gruppe, viel Übungszeit auf dem Platz und ein Ausbilder, der genau merkt, wo man noch unsicher ist. Kann ich nur empfehlen.', 2);
INSERT INTO testimonial (name, course, rating, quote, sort_order) VALUES ('Sofia R.', 'Fahrstunden Auto (Italienisch)', 5, 'Es war mir wichtig, den Unterricht auf Italienisch zu machen – das hat bei Haudi''s problemlos geklappt und mir viel Sicherheit gegeben.', 3);
