INSERT INTO regulation_section (vehicle_type, question, answer, sort_order) VALUES ('AUTO', 'Wie läuft der Weg zum Führerausweis Kategorie B seit OPERA-3 ab?', '["Seit der Reform OPERA-3 (in Kraft seit 1. Januar 2021) gilt ein vierstufiges Modell für die Kategorie B (Auto).","1. Theorieprüfung: frühestens ab 17 Jahren möglich, nach Bestehen erhältst du den Lernfahrausweis.","2. Praktische Prüfung: frühestens ab 18 Jahren, Voraussetzung sind 8 Stunden Verkehrskundeunterricht (VKU). Wer den Lernfahrausweis vor dem 20. Altersjahr erwirbt, muss zusätzlich mindestens 1 Jahr Lernphase durchlaufen.","3. Führerausweis auf Probe: gilt 3 Jahre. Innert der ersten 12 Monate ist ein Weiterbildungskurs (WAB, 1 Tag / 7 Stunden) obligatorisch, insgesamt sind 15 Ausbildungsstunden vorgeschrieben.","4. Definitiver Führerausweis: ab 21 Jahren und ohne Widerhandlungen während der Probezeit unbefristet gültig."]'::jsonb, 0);
INSERT INTO regulation_section (vehicle_type, question, answer, sort_order) VALUES ('AUTO', 'Was ändert sich bei Automatik- und Handschaltung?', '["Wer die praktische Prüfung in einem Fahrzeug mit Automatikgetriebe ablegt, darf danach auch manuell geschaltete Fahrzeuge führen – die frühere Einschränkung auf Automatikfahrzeuge wurde per OPERA-3 aufgehoben."]'::jsonb, 1);
INSERT INTO regulation_section (vehicle_type, question, answer, sort_order) VALUES ('AUTO', 'Was passiert, wenn ich den Lernfahrausweis vor dem 20. Altersjahr erwerbe?', '["In diesem Fall ist eine mindestens einjährige Lernphase mit dem Lernfahrausweis vorgeschrieben, bevor du zur praktischen Prüfung antreten kannst."]'::jsonb, 2);
INSERT INTO regulation_section (vehicle_type, question, answer, sort_order) VALUES ('AUTO', 'Was beinhaltet der Weiterbildungskurs (WAB) auf dem Führerausweis auf Probe?', '["Der obligatorische Weiterbildungskurs dauert einen Tag (7 Stunden) und muss innert der ersten 12 Monate nach Erhalt des Führerausweises auf Probe absolviert werden. Schwerpunkte sind unter anderem Gefahrenbremsung und energieeffizientes Fahren."]'::jsonb, 3);
INSERT INTO regulation_section (vehicle_type, question, answer, sort_order) VALUES ('MOTORRAD', 'Was hat sich für Motorradfahrer:innen mit OPERA-3 geändert?', '["OPERA-3 harmonisiert die Schweizer Motorrad-Kategorien mit den EU-Vorgaben und passt die Alterslimiten an. Wer die leistungsstärksten Motorräder (Kategorie A unbeschränkt) fahren will, muss künftig zuerst mindestens 2 Jahre ein auf 35 kW beschränktes Motorrad der Kategorie A gefahren haben."]'::jsonb, 0);
INSERT INTO regulation_section (vehicle_type, question, answer, sort_order) VALUES ('MOTORRAD', 'Welche Kategorien und Alterslimiten gelten?', '["A1 beschränkt (45 km/h): ab 15 Jahren, Theorie- und praktische Prüfung sowie Nothelferausweis nötig, 12 Stunden praktische Grundausbildung.","A1 (125cm³): ab 16 Jahren, 12 Stunden praktische Grundausbildung, Kursbestätigung erforderlich.","A beschränkt (35 kW): ab 18 Jahren, Theorieprüfung (entfällt bei vorhandenem Ausweis Kategorie B), 12 Stunden praktische Grundausbildung, praktische Prüfung.","A unbeschränkt: ab 20 Jahren, sofern mindestens 2 Jahre Fahrpraxis mit einem 35-kW-Motorrad (Kategorie A beschränkt) vorliegen; Einzelfahrstunden und praktische Prüfung."]'::jsonb, 1);
INSERT INTO regulation_section (vehicle_type, question, answer, sort_order) VALUES ('MOTORRAD', 'Ist die praktische Grundausbildung obligatorisch?', '["Ja – die 12-stündige praktische Grundausbildung (unser Motorradgrundkurs) ist für alle Kategorien A1/A Pflicht und Voraussetzung für die Anmeldung zur praktischen Prüfung."]'::jsonb, 2);
INSERT INTO process_step (step, title, description, sort_order) VALUES (1, 'Nothelferkurs absolvieren', 'Bevor du dich für den Lernfahrausweis anmelden kannst, brauchst du einen gültigen Nothelferkurs-Ausweis. Wir bieten den Kurs laufend als Wochenend- oder Abendkurs an – die Bescheinigung ist 6 Jahre gültig.', 0);
INSERT INTO process_step (step, title, description, sort_order) VALUES (2, 'Gesuch einreichen', 'Das Gesuch um einen Lern- oder Fahrausweis lädst du von der Website deines Kantons herunter und reichst es mit Passfoto, Nothelferausweis und einem Sehtest von einem anerkannten Augenarzt oder Optiker ein.', 1);
INSERT INTO process_step (step, title, description, sort_order) VALUES (3, 'Identität bestätigen', 'Mit dem ausgefüllten Gesuch und einem gültigen Ausweisdokument (ID oder Pass) meldest du dich persönlich bei der Einwohnerkontrolle deiner Wohngemeinde.', 2);
INSERT INTO process_step (step, title, description, sort_order) VALUES (4, 'Theorieprüfung bestehen', 'Das Strassenverkehrsamt schickt dir das Aufgebot zur Theorieprüfung zu. Wir helfen dir bei der Vorbereitung – zum Beispiel mit unseren kostenlosen Bögle-Übungslektionen. Nach bestandener Prüfung erhältst du deinen Lernfahrausweis.', 3);
INSERT INTO process_step (step, title, description, sort_order) VALUES (5, 'VKU & Fahrstunden', 'Melde dich bei uns für den Verkehrskundeunterricht (VKU) und deine Fahrstunden an. Wir bilden dich individuell, geduldig und wenn gewünscht in deiner Muttersprache aus.', 4);
INSERT INTO process_step (step, title, description, sort_order) VALUES (6, 'Praktische Prüfung', 'Sobald du und dein/e Fahrlehrer/in bereit seid, meldest du dich zur praktischen Prüfung an. Wir bereiten dich gezielt auf die Prüfungsroute und die häufigsten Situationen vor – und feiern mit dir, wenn du bestanden hast.', 5);
INSERT INTO site_settings (id, name, legal_name, short_name, url, description, phone, phone_display, email, address_street, address_postal_code, address_city, address_region, address_country, geo_latitude, geo_longitude, founders, opening_hours, socials) VALUES (1, 'Haudis Verkehrsschule', 'Haudi''s Fahrschule, Bruno & Ausilia Haudenschild', 'Haudi''s Fahrschule', 'https://www.haudis-verkehrsschule.ch', 'Haudis Verkehrsschule in Baden bildet dich zum Auto- und Motorradfahren aus – mit eigenem, modernem Verkehrszentrum, individueller Betreuung und Unterricht in mehreren Sprachen.', '+41 79 604 44 44', '079 604 44 44', 'info@haudi.ch', 'Haselstrasse 33', '5400', 'Baden', 'AG', 'CH', 47.4788, 8.3104, '["Bruno Haudenschild","Ausilia Haudenschild"]'::jsonb, '[{"days":"Mo–Fr","hours":"08:00–12:00, 13:30–18:30"},{"days":"Sa","hours":"nach Vereinbarung"}]'::jsonb, '[]'::jsonb);
